-	if len(parts) < 2 {
-		return ""
-	}
-	typePart := parts[1]
-	// Extract type before underscore and number
-	for i, c := range typePart {
-		if c == '_' {
-			return typePart[:i]
-		}
-	}
-	return typePart
-}

